#include <bits/stdc++.h>
using namespace std;
#define pii pair<int,int>
#define int long long
const int maxn=1e5+5;
struct node {
	vector<pii>e;
	int b,d=INT_MAX;
} v[maxn];
queue<int> q;
void cheek(int id,int dis) {
	if(dis<v[id].d) {
		v[id].d=dis;
		if(!v[id].b) {
			v[id].b=1;
			q.push(id);
		}
	}

}
int n,m,s;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>s;
	for(int i=1,x,y,z;i<=m;i++){
		cin>>x>>y>>z;
		v[x].e.emplace_back(y,z);
	}
	cheek(s,0);
	while(q.size()){
		auto p=q.front();q.pop();
		v[p].b=0;
		for(auto e:v[p].e){
			cheek(e.first,e.second+v[p].d);
		}
	}
	for(int i=1;i<=n;i++){
		cout<<v[i].d<<" ";
	}
	return 0;
}
